import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.data.elasticsearch.client.RestClients;
import org.springframework.data.elasticsearch.core.ElasticsearchRestTemplate;
import org.springframework.data.elasticsearch.core.mapping.IndexCoordinates;
import org.springframework.data.elasticsearch.core.query.IndexQuery;
import org.springframework.data.elasticsearch.core.query.NativeSearchQuery;
import org.springframework.data.elasticsearch.core.query.NativeSearchQueryBuilder;
import org.springframework.data.elasticsearch.core.query.Query;
import org.springframework.data.elasticsearch.core.query.QueryBuilder;
import org.springframework.data.elasticsearch.core.query.QueryStringQueryBuilder;
import org.springframework.data.elasticsearch.repository.ElasticsearchRepository;
import org.springframework.stereotype.Service;

import java.util.List;

@SpringBootApplication
public class ProductSearchApplication {
    public static void main(String[] args) {
        SpringApplication.run(ProductSearchApplication.class, args);
    }

    @Bean
    public ElasticsearchRestTemplate elasticsearchTemplate() {
        return new ElasticsearchRestTemplate(RestClients.create("http://localhost:9200").rest());
    }
}

@Entity
class Product {
    @Id
    private String id;
    private String name;
    private String description;
    private double price;
    private String category;

    // Getters and Setters
}

interface ProductRepository extends ElasticsearchRepository<Product, String> {
    List<Product> findByCategory(String category);
}

@Service
class ProductService {
    private final ElasticsearchRestTemplate elasticsearchTemplate;
    private final ProductRepository productRepository;

    public ProductService(ElasticsearchRestTemplate elasticsearchTemplate, ProductRepository productRepository) {
        this.elasticsearchTemplate = elasticsearchTemplate;
        this.productRepository = productRepository;
    }

    public void indexProduct(Product product) {
        IndexQuery indexQuery = new IndexQuery();
        indexQuery.setId(product.getId());
        indexQuery.setObject(product);
        elasticsearchTemplate.index(indexQuery, IndexCoordinates.of("products"));
    }

    public List<Product> searchProducts(String query) {
        Query searchQuery = new NativeSearchQueryBuilder()
                .withQuery(new QueryStringQueryBuilder(query))
                .build();
        return elasticsearchTemplate.queryForList(searchQuery, Product.class);
    }

    public List<Product> getProductsByCategory(String category) {
        return productRepository.findByCategory(category);
    }
}

@RestController
@RequestMapping("/products")
class ProductController {
    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
    }

    @PostMapping
    public ResponseEntity<Void> addProduct(@RequestBody Product product) {
        productService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED).build();
    }

    @GetMapping("/search")
    public ResponseEntity<List<Product>> search(@RequestParam String query) {
        List<Product> products = productService.searchProducts(query);
        return ResponseEntity.ok(products);
    }

    @GetMapping("/category/{category}")
    public ResponseEntity<List<Product>> getByCategory(@PathVariable String category) {
        List<Product> products = productService.getProductsByCategory(category);
        return ResponseEntity.ok(products);
    }
}